const results = [];
const inputs = $input.all();
// This line literally reaches back in time to grab the original data before the HTTP node wiped it
const editFieldsData = $('Edit Fields').all(); 

for (let i = 0; i < inputs.length; i++) {
  const item = inputs[i];
  // Grab the topic from the exact same row in the previous node
  const topic = editFieldsData[i].json.topic || editFieldsData[i].json[" Topic"] || "Unknown";
  const articles = item.json.articles || [];

  for (const article of articles) {
    results.push({
      json: {
        title: article.title,
        url: article.url,
        description: article.description,
        source: "NewsAPI",
        topic: topic
      }
    });
  }
}

return results;

const results = [];
const inputs = $input.all();
const editFieldsData = $('Edit Fields1').all(); 

for (let i = 0; i < inputs.length; i++) {
  const item = inputs[i];
  const topic = editFieldsData[i].json.topic || editFieldsData[i].json[" Topic"] || "Unknown";

  const hits = item.json.hits || [];

  for (const hit of hits) {
    results.push({
      json: {
        title: hit.title || "No Title",
        url: hit.url || `https://news.ycombinator.com/item?id=${hit.objectID}`,
        description: hit.story_text || "",
        source: "Hacker News", 
        topic: topic
      }
    });
  }
}

return results;

const items = $input.all();
const processedArticles = [];

// Reach back to the Merge node to grab the original titles, urls, sources, and topics!
const originalData = $('Merge').all(); 

// 1. Parse the AI responses & merge back the original data
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const original = originalData[i]?.json || {}; // Safely get the original article properties

  try {
    const raw = item.json.text || "{}";
    const cleaned = raw.replace(/```json|```/g, "").trim();
    const parsed = JSON.parse(cleaned);

    // Only keep high-signal articles (Score >= 6)
    if (parsed.relevance_score >= 6) {
      processedArticles.push({
        title: original.title || "No Title",         // FIXED: pulling from original data
        url: original.url || "#",                   // FIXED: pulling from original data
        description: original.description || "", 
        source: original.source || "Unknown",       // FIXED: pulling from original data
        topic: original.topic || "General",         // FIXED: pulling from original data
        relevance_score: parsed.relevance_score,
        sentiment: parsed.sentiment || "Neutral",
        summary: parsed.summary || "No summary provided."
      });
    }
  } catch (e) {
    // Skip items if AI returned bad JSON
    continue;
  }
}

// 2. Sort by highest score first
processedArticles.sort((a, b) => b.relevance_score - a.relevance_score);

// 3. Find Top Pick (Highest Score)
const topPick = processedArticles.length > 0 ? processedArticles[0] : null;

// 4. Group remaining articles by Topic
const grouped = {};
for (const article of processedArticles) {
  const topic = article.topic || "General";
  if (!grouped[topic]) grouped[topic] = [];
  grouped[topic].push(article);
}

// 5. Build HTML Styling
const sentimentColor = { "Positive": "#46d160", "Negative": "#ea0027", "Neutral": "#7193ff" };
const sourceColor = { "NewsAPI": "#ff4500", "Hacker News": "#ff6314" };

let topicSections = "";
for (const [topic, articles] of Object.entries(grouped)) {
  const articleCards = articles.map(a => `
    <div style="background:#1a1a2e;border-radius:8px;padding:16px;margin-bottom:12px;border-left:3px solid #7193ff;">
      <div style="display:flex;gap:8px;margin-bottom:8px;">
        <span style="background:${sourceColor[a.source] || '#7193ff'};color:#fff;font-size:11px;padding:2px 8px;border-radius:4px;">${a.source}</span>
        <span style="background:${sentimentColor[a.sentiment] || '#7193ff'};color:#fff;font-size:11px;padding:2px 8px;border-radius:4px;">${a.sentiment}</span>
        <span style="background:#2a2a4a;color:#aaa;font-size:11px;padding:2px 8px;border-radius:4px;">Score: ${a.relevance_score}/10</span>
      </div>
      <a href="${a.url}" style="color:#e0e0ff;font-size:15px;font-weight:600;text-decoration:none;">${a.title}</a>
      <p style="color:#aaa;font-size:13px;margin:8px 0 0 0;">${a.summary}</p>
    </div>
  `).join("");

  topicSections += `
    <div style="margin-bottom:32px;">
      <h2 style="color:#7193ff;font-size:18px;margin:0 0 16px 0;padding-bottom:8px;border-bottom:1px solid #2a2a4a;">📌 ${topic}</h2>
      ${articleCards}
    </div>
  `;
}

const topPickHTML = topPick ? `
  <div style="background:#1a2a1a;border:1px solid #46d160;border-radius:8px;padding:20px;margin-bottom:32px;">
    <div style="color:#46d160;font-size:12px;font-weight:700;letter-spacing:1px;margin-bottom:8px;">⭐ TOP PICK OF THE WEEK</div>
    <a href="${topPick.url}" style="color:#e0e0ff;font-size:16px;font-weight:700;text-decoration:none;">${topPick.title}</a>
    <p style="color:#aaa;font-size:13px;margin:8px 0 0 0;">${topPick.summary}</p>
    <div style="margin-top:8px;">
      <span style="color:#46d160;font-size:12px;">Topic: ${topPick.topic} · Score: ${topPick.relevance_score}/10</span>
    </div>
  </div>
` : "<p style='color:#aaa;'>No articles scored high enough this week.</p>";

const today = new Date().toLocaleDateString("en-IN", { weekday: "long", year: "numeric", month: "long", day: "numeric" });

const html = `
<!DOCTYPE html>
<html>
<head><meta charset=\"UTF-8\"></head>
<body style="margin:0;padding:0;background:#0d0d1a;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;">
  <div style="max-width:640px;margin:0 auto;padding:32px 16px;">

    <!-- Header -->
    <div style="text-align:center;margin-bottom:32px;">
      <div style="font-size:28px;font-weight:800;color:#e0e0ff;letter-spacing:-0.5px;">📡 TrendPulse</div>
      <div style="color:#7193ff;font-size:13px;margin-top:4px;">Your weekly AI intelligence digest</div>
      <div style="color:#555;font-size:12px;margin-top:4px;">${today}</div>
    </div>

    <!-- Top Pick -->
    ${topPickHTML}

    <!-- Topic Sections -->
    ${topicSections}

    <!-- Footer -->
    <div style="text-align:center;padding-top:24px;border-top:1px solid #2a2a4a;">
      <p style="color:#444;font-size:11px;">Generated automatically by TrendPulse · n8n + Gemini</p>
    </div>

  </div>
</body>
</html>
`;

return [{ json: { html, subject: `📡 TrendPulse Weekly Digest — ${today}` } }];

